              <h1 class="text-2xl font-black text-slate-900 tracking-tight uppercase">¡Hola, {{ profile.nombres }}!</h1>
              <p class="text-slate-500 text-xs mt-1">Bienvenido a tu Campus Virtual. Continúa aprendiendo y alcanza tus metas.</p>
            </div>
          </div>
          <a 
            routerLink="/dashboard/mis-cursos"
            class="px-5 py-3 bg-slate-900 text-white text-xs font-bold uppercase tracking-widest hover:bg-slate-800 transition-colors rounded-none shadow-[2px_2px_0px_0px_rgba(0,0,0,0.15)] flex items-center gap-2">
            <span>Ir a Mis Cursos</span>
            <span class="material-symbols-outlined text-sm">arrow_forward</span>
          </a>
        </div>
      </div>

