        <div class="border border-slate-200 bg-white p-6 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] flex items-center justify-between">
          <div>
            <span class="text-[10px] font-black text-slate-400 uppercase tracking-widest">Cursos Completados</span>
            <h3 class="text-4xl font-black text-slate-900 mt-2 tracking-tight">{{ studentCursosCompletados }}</h3>
            <p class="text-[10px] text-emerald-600 font-bold mt-1.5 flex items-center gap-1">
              <span class="w-1.5 h-1.5 bg-emerald-500 rounded-full"></span>
              {{ studentCursosCompletados }} terminados al 100%
